data.prompt:
{
  "ugc_selfie_realism_layer": {
    "version": "1.0",
    "description": "Perceptual style layer extracted from real UGC smartphone selfies. Apply to AI image prompts to achieve authentic creator-content feel. Overall feeling is that signature Tiktok native organic content feel; your friend face timed you to show you something cool",

    "imperfections": {
      "focus": "Slightly soft overall sharpness, never razor-crisp edge-to-edge. One zone of the image is noticeably sharper than the rest — usually the face or product — while periphery goes gently mushy.",
      "noise_grain": "Faint digital grain visible in shadow areas and flat surfaces like walls, consistent with phone sensors pushing in mixed light. Not film grain — smaller, more uniform, slightly color-speckled.",
      "compression": "Subtle JPEG muddiness in gradients — sky-to-wall transitions, dark hair against dark backgrounds. Fine details like individual hairs or fabric weave blur into each other at distance.",
      "lens_artifacts": "Mild barrel distortion at close range — extended hands or products held toward camera appear slightly oversized relative to the body. Edges of frame show very slight warping on straight lines like door frames or shelves.",
      "highlight_behavior": "Hot spots blow out without graceful rolloff — forehead shine, window light, and reflective product surfaces clip to flat white patches with no recovered detail."
    },

    "pose_and_framing": {
      "camera_distance": "Arm's length or closer. The camera is always within touching distance of the subject, creating an intimate, slightly too-close feel. Never more than three feet away.",
      "angle": "Slightly above eye level or dead-on. Never dramatically high or low — just the natural tilt of a hand holding a phone at face height or slightly raised.",
      "composition": "Face fills 50-80% of the vertical frame. Off-center and imprecise — the subject drifts toward one side, chin gets cropped, top of head gets cut. Subject is organic / imperfectly naturally postured in the screen, not directly straight up in the middle of the scene. It feels like your friend set up her phone on facetime to show you something cool that she found",
      "body_crop": "Cuts off mid-chest or mid-arm in ways a photographer would never choose. Products or hands enter the frame from unexpected angles, partially occluding the face.",
      "gaze": "Eyes look at the front-facing camera lens — slightly off from where a 'real' camera would be. Creates that characteristic phone-selfie eye contact that lands just a few degrees wrong.",
      "expression": "Mid-motion captures — mouths slightly open, eyes mid-blink, expressions caught between poses. Feels like one frame pulled from a burst rather than a held smile."
    },

    "lighting_character": {
      "source": "Single dominant light source, almost always a nearby window. Light wraps around one side of the face and falls off on the other with no fill. No evidence of reflectors, ring lights, or multiple sources.",
      "quality": "Soft but directional — you can tell where the window is, but the shadows aren't sharp-edged. Shadows on the neck and under the chin are dark and unrecovered.",
      "color_temperature": "Warm and inconsistent. Skin tones lean golden-amber from natural light, but background areas illuminated by indoor bulbs or mixed daylight shift slightly cooler or greener. The white balance feels like auto-mode splitting the difference rather than being set deliberately.",
      "dynamic_range": "Narrow. Bright areas and dark areas exist in the same frame but the phone can't hold both — windows blow out to white rectangles, corners of rooms go murky-dark. The subject's face sits in the usable middle zone.",
      "skin_glow": "Specular highlights on forehead, nose bridge, and cheekbones read as natural oil and moisture, not studio lighting. Small, intense, slightly irregular catchlights rather than smooth gradients."
    },

    "skin_and_texture_realism": {
      "pores_and_detail": "Visible skin texture at close range — pores on cheeks and nose, fine lines around eyes and mouth. Not airbrushed but not exaggerated. The phone's processing smooths slightly but doesn't eliminate.",
      "blemishes": "Small imperfections present — a spot here, slight redness there, uneven tone across the forehead vs cheeks. Nothing dramatic, just the normal variation phones don't fully filter out.",
      "makeup_appearance": "Where makeup exists, it looks like real product on real skin — slightly settled into pores, a little patchy at the hairline or jawline. Lipstick or gloss catches light unevenly.",
      "hair_rendering": "Individual strands visible near the face but clumping into masses at the edges. Flyaways and frizz catch backlight and glow. Curly or textured hair reads as a soft volume rather than defined individual coils at distance.",
      "moisture_and_sheen": "Skin looks alive — slight dewiness on the T-zone, dry-matte on cheeks. Serum or product on skin catches light in thick, viscous-looking drops rather than even sheen."
    },

    "background_authenticity": {
      "environment": "Lived-in personal spaces — unmade beds with mismatched pillows, cluttered shelves, houseplants in various states of health, real furniture with visible wear. Nothing is styled for the shot.",
      "depth_separation": "Shallow separation between subject and background but not creamy bokeh — more like the background is just slightly less sharp, the way phone portrait modes approximate depth. Some phones show hard-edged masking artifacts where hair meets background.",
      "clutter_and_objects": "Random real-life objects visible — chargers, bottles on shelves, pillows, hanging plants, jewelry on the person. These aren't props; they're incidental details the creator didn't think to remove.",
      "color_palette": "Backgrounds tend toward muted, warm neutrals — beige walls, wood tones, earth-colored textiles — with small pops of uncoordinated color from personal items. Never a clean white studio wall.",
      "scale_cues": "Background objects establish a real room — you can sense the ceiling height, the proximity of furniture, the size of the space. The environment reads as a bedroom, bathroom, or small apartment, not an open or ambiguous void."
    }
  }
}

data.outputText:
Use the following JSON prompt, the attached hair reference image, and the product reference image ensuring it integrates into the shot naturally (the entirety of both bottles are fully visible) and is held towards the camera so that product text remains readable, Generate the image.  {
"brand_injection": {
"aesthetic_overlay": "A highly detailed, sun-drenched vibrant Brazilian Tropicália aesthetic. Rich color palette of emerald greens, canary yellows, ultramarine blue, and warm terracotta. Textures of glazed mosaic tiles, raw mahogany wood, woven rattan, and lush broadleaf jungle foliage. Indoor-outdoor living spaces with archways overlooking the sparkling ocean. Bohemian vintage lifestyle, caipirinhas on sandy beaches, Copacabana wave patterns, retro 70s geometric prints. Shot on 35mm film, warm color grading, high saturation, nostalgic, relaxed, effortless coastal beauty, culturally rich, high aesthetic travel editorial photography."
},
"scene_world": {
"setting": "a sun-drenched, semi-cluttered artsy bedroom blending tropical modernism with rustic bohemian architecture — warm varnished teak wood, raw terracotta, and woven rattan surfaces throughout, wide open archways revealing a vibrant blue sky, hard midday sunlight pouring in, feeling effortlessly chic, culturally vibrant, and lived-in",
"color_palette": "hard midday sunlight illuminating warm terracotta/clay floor tiles, deep emerald/lush tropical green monstera leaves, a vibrant ultramarine blue ceramic mug on the dresser, and a canary yellow woven hammock chair in the corner, with crisp white blown-out window light",
"light_source": "single dominant open window or archway to camera-right letting in hard, direct midday tropical sunlight, no fill source, no reflector, no studio setup",
"light_quality": "hard, direct sunlight creating sharp, deep shadows mixed with dappled light filtering through lush foliage, visible bright wrap on the lit side of the face, shadow side dark and unrecovered, neck and under-chin shadows deep",
"light_temperature": "warm, highly saturated midday tropical brilliance on skin and wood surfaces — auto white balance drift with background areas shifting slightly cooler or greener, not corrected, splitting the difference like a phone camera",
"atmosphere": "joyful, carefree, and sun-kissed, living a slow, beautiful life on the coast of South America, surrounded by art, nature, and endless summer in a deeply relaxing, culturally immersive space"
},
"environment": {
"background_elements": "built-in raw wood cabinetry and slatted wooden ceilings, an unmade bed with faded vintage denim and lightweight cotton throws, a large potted indoor palm plant in a rough woven rattan basket, hanging vines framing an open archway with a visible blue sky beyond, a section of intricate floral/geometric ceramic tile pattern visible on the wall behind the bed, a raw terracotta planter holding a waxy broadleaf monstera, random real-life clutter including a smooth coconut shell bowl and chargers on a warm varnished teak dresser",
"depth_layers": "Foreground: the edge of a warm varnished teak dresser with a smooth coconut shell bowl and a vibrant ultramarine blue ceramic mug entering the frame. Midground: subject seated in the bedroom, holding the products at chest height, correctly scaled to the room. Background: built-in raw wood cabinetry, a large indoor palm plant in a woven rattan basket, a wall section featuring an intricate floral/geometric ceramic tile pattern, and an open archway revealing a bright blue sky",
"depth_separation": "shallow separation between subject and background — phone portrait approximation, background only slightly softer than subject, possible hard-edged masking artifact at hair edges, not cinematic bokeh",
"scale_cues": "compact, lived-in bedroom scale — teak dresser close to the camera, slatted wooden ceiling implied just out of frame, archway and built-in cabinetry spatially consistent with the subject's seated position, establishing a real room rather than a void"
},
"subject": {
"age": "early 20s",
"gender": "female",
"ethnicity": "Brazilian American",
"expression": "mouth slightly open, caught between thoughts, mid-motion, not posed, feeling like a frame pulled from a burst",
"gaze": "into the front-facing lens, landing a few degrees off, characteristic phone-selfie eye contact"
},
"hair": {
"curl_pattern": "3A-3B defined, bouncy curls, shiny and healthy, framing the face with a lived-in softness and glossy ribbon-like separation",
"volume": "massive volume — full, thick halo shape cascading heavily past the shoulders while the top stays lifted and beautifully tousled",
"part_placement": "soft, imperfect side part, falling naturally rather than rigidly styled",
"frizz_level": "low-moderate — polished and defined through the main lengths, slightly diffused and airy at the outer edges",
"flyaways": "fine halo frizz and individual flyaway strands around the crown and hairline catching the hard backlight and glowing at the edges",
"reference_note": "hair reference image provided — match curl pattern and volume, not color"
},
"skin_and_appearance": {
"skin_texture": "visible pores on cheeks and nose, fine lines around eyes, real phone-softened detail, never airbrushed or poreless, minor natural blemishes",
"skin_finish": "dewy T-zone, matte outer cheeks, small intense irregular specular catches on forehead, nose bridge, and cheekbones reading as natural moisture and sweat in the humid heat",
"makeup": "defined filled brows, visible winged eyeliner and long dark lashes, warm bronzer and peach blush sitting high on the cheekbones, overlined lips with a thick glossy nude-pink finish catching light unevenly, slightly settled into pores, reading as real makeup on real skin",
"clothing": "casual beach-to-street style — a relatively modest lightweight cotton top in sandy beige with a subtle 70s retro graphic print, faded vintage denim shorts just visible at the bottom edge"
},
"product_handling": {
"quantity": "2",
"hand_position": "both hands raised, one bottle in each hand, symmetrical but not perfectly matched, held at slightly different heights with a solid grip",
"orientation": "both labels angled toward camera, readable but not rigidly straight-on, minor surface glare",
"distance_from_camera": "mid-foreground, slightly closer to the lens than the subject's face, prominent but not dominating",
"label_visibility": "primary label text readable and facing forward — not mirrored, not rotated, minor glare and curvature distortion acceptable",
"scale_relative_to_hands": "bottles are massive and heavy — each reaches from the palm to mid-forearm, filling the grip across its wide diameter, reading as weighty 1kg salon-size packaging",
"integration_note": "casually lifted into frame, not arranged, she's showing you the heavy bottles on a facetime call, not presenting to camera"
},
"camera": {
"distance": "arm's length or closer, consistent with a phone propped up on a stable surface or tripod right in front of her",
"angle": "dead-on to slightly above eye level, natural smartphone placement",
"framing": "face fills 50-70% of vertical frame, off-center and imprecise drift, organic and imperfectly postured",
"crop": "top of voluminous hair lightly clipped by the frame top, mid-chest at bottom, ways a photographer would never choose",
"aspect_ratio": "16:9"
},
"imperfections": {
"focus_quality": "one sharp zone on the face and front labels — edges and background go gently mushy, never razor-crisp edge-to-edge",
"noise_grain": "faint digital color-speckled grain in shadows and flat wall surfaces, phone sensor pushing in mixed light, not film grain",
"compression_artifacts": "JPEG muddiness in gradients, sky-to-wall transitions, and dark hair edges blurring into the background",
"lens_distortion": "mild barrel distortion — large heavy products held forward appear slightly oversized, straight edges of the built-in cabinetry warp near frame boundary",
"highlight_clipping": "bright blue sky in the archway, window light, and glossy product surfaces clip to flat white patches, no recovered detail"
},
"mood": {
"overall_feel": "a joyful, sun-drenched UGC moment — a Brazilian American creator casually showing her massive haircare bottles in her artsy, semi-cluttered bedroom, radiating an energetic yet deeply relaxing coastal bohemian vibe",
"authenticity_cues": "the two heavy bottles sit at slightly asymmetrical heights with visible label glare; a random phone charger sits tangled on the teak dresser; her expression is caught mid-thought with a slightly open mouth"
}
}

